const j = $input.first().json || {};
const execution = j.execution || {};
const err = execution.error || j.error || {};
const lastNode = execution.lastNodeExecuted || err.node || 'unknown';
const wfName = (j.workflow && j.workflow.name) || j.workflow_name || 'unknown';
const wfId = (j.workflow && j.workflow.id) || j.workflow_id || 'unknown';
const execId = execution.id || j.execution_id || 'unknown';
const execUrl = execution.url || (j.workflow_execution_url) || null;
const message = err.message || j.message || 'No error message';
const stack = err.stack || err.description || '';

const raw = String(message).toLowerCase();
let severity = 'error';
if (/oom|out of memory|cuda out of memory/.test(raw)) severity = 'critical';
else if (/timeout|timed out|deadline/.test(raw)) severity = 'warning';
else if (/connection refused|econnref|name or service not known|connect timeout/.test(raw)) severity = 'warning';

const slack_message = [
  `:rotating_light: *n8n workflow error* — \`${wfName}\``,
  `\u2022 Node: \`${lastNode}\``,
  `\u2022 Severity: \`${severity}\``,
  `\u2022 Message: ${message}`,
  execUrl ? `\u2022 Execution: ${execUrl}` : `\u2022 Execution ID: \`${execId}\``,
].join('\n');

console.log('[error-handler]', { wfName, lastNode, severity, execId });

return [{
  json: {
    workflow_name: wfName,
    workflow_id: wfId,
    execution_id: execId,
    execution_url: execUrl,
    failed_node: lastNode,
    error_message: message,
    stack_trace: stack,
    severity,
    slack_message,
    detected_at: new Date().toISOString(),
  }
}];
